function Build-KW($area, $cat, $groups) {
  $nl="`r`n"; $h="  <!-- 서비스 키워드 -->$nl  <h2 class=""section-title"">$area $cat 서비스 키워드</h2>$nl"
  foreach ($g in $groups) {
    $chips = ($g.k -split ",") | ForEach-Object { "<span class=""kwchip"">$_</span>" }
    $h += "  <div class=""service-block""><h3>$($g.t)</h3><div class=""keyword-list"">$($chips -join '')</div></div>$nl"
  }
  return $h
}
function Build-Price($area, $cat, $rows) {
  $nl="`r`n"
  $h="$nl  <!-- 가격 안내 -->$nl  <h2 class=""section-title"">$area $cat 예상 비용 안내</h2>$nl"
  $h+="  <div class=""map-info"" style=""padding:0;overflow:hidden"">$nl"
  $h+="  <table style=""width:100%;border-collapse:collapse;font-size:14px"">$nl"
  $h+="    <thead><tr style=""background:#e8edf8;color:#0d2e8a""><th style=""text-align:left;padding:11px 16px;font-weight:800"">서비스 항목</th><th style=""text-align:right;padding:11px 16px;font-weight:800"">예상 비용</th></tr></thead>$nl  <tbody>$nl"
  foreach ($r in $rows) {
    $h+="    <tr style=""border-top:1px solid #dde3ef""><td style=""padding:10px 16px"">$($r.n)</td><td style=""padding:10px 16px;text-align:right;font-weight:800;color:#ff6b35"">$($r.p)</td></tr>$nl"
  }
  $h+="  </tbody></table>$nl  </div>$nl"
  $h+="  <p style=""font-size:12px;color:#888;margin:8px 2px 0"">* 위 금액은 업계 평균 기준 참고용이며, 현장 상황·자재·규모에 따라 달라집니다. 정확한 견적은 상담 시 무료로 안내해 드립니다.</p>$nl$nl  "
  return $h
}

$done=0; $skip=0; $prev=$null
foreach ($entry in $D.GetEnumerator()) {
  $cat = $entry.Key
  $d   = $entry.Value
  $catDir = Join-Path $siteRoot $cat
  if (-not (Test-Path $catDir)) { Write-Host "[DEBUG] no-dir: $cat"; continue }
  $catN=0
  foreach ($file in (Get-ChildItem $catDir -Recurse -Filter "*.html")) {
    if ($file.Name -notmatch '^\d+\.html$') { continue }
    $c=[IO.File]::ReadAllText($file.FullName,[Text.Encoding]::UTF8)
    $area=""
    if ($c -match '(?s)class="hero-title">[^<]+<br>\s*([^\r\n<]+?)\s*<em>') { $area=$matches[1].Trim() }
    if (-not $area -and $c -match '<title>([^|<]+)') { $area=$matches[1].Trim() -replace '\s+\S+$','' }
    if (-not $area) { $skip++; continue }

    # 기존에 가격 블록이 있으면 제거(재실행 idempotent)
    $c=[regex]::Replace($c,'(?s)\s*<!-- 가격 안내 -->.*?(?=\s*<!-- 지도|\s*<h2 class="section-title">[^<]*지도)','')
    # 키워드+가격 = 서비스 키워드 ~ 지도 직전 구간 교체
    $newBlock = (Build-KW $area $cat $d.kw) + (Build-Price $area $cat $d.price)
    $pat='(?s)<!-- 서비스 키워드 -->.*?(?=\s*<!-- 지도|\s*<h2 class="section-title">[^<]*지도)'
    if ($c -notmatch $pat) { $skip++; continue }
    $c2=[regex]::Replace($c,$pat,$newBlock)

    if ($null -eq $prev) {
      $prev=$file.FullName
      Write-Host "===== 미리보기: $prev ====="
      $i=$c2.IndexOf('<!-- 서비스 키워드 -->')
      Write-Host $c2.Substring($i,[Math]::Min(1400,$c2.Length-$i))
      Write-Host "===== /미리보기 ====="
    }
    if ($Apply) { [IO.File]::WriteAllText($file.FullName,$c2,(New-Object Text.UTF8Encoding $false)) }
    $done++; $catN++
  }
  Write-Host "[DEBUG] $cat -> $catN"
}
$mode = if($Apply){"적용완료"}else{"미리보기(미적용)"}
Write-Host ""
Write-Host "[$mode] 처리: $done | 건너뜀: $skip"
